[asy]
unitsize(0.5 cm);

pair A = (-6,-3), B = (6,3);

draw((-8,0)--(8,0));
draw((0,-4)--(0,4));
draw((0,0)--A,dashed);
draw((0,0)--B,dashed);

dot("$-6 - 3i$", A, SW);
dot("$6 + 3i$", B,  NE);
[/asy]

